CREATE OR REPLACE FUNCTION fpb_gos_month_loan (as_conno char,ai_year integer,ai_month integer) RETURNS bigint AS $body$
DECLARE

  ldt_date_fr timestamp(0);
  ldt_date_to timestamp(0);
  ldc_amount bigint;

BEGIN
  ldt_date_fr := to_date('1/'||trim(both ai_month)||'/'||trim(both ai_year),'dd/mm/yyyy');
  ldt_date_to := pka_srv_datetime.fp_lastdayofmonth(ldt_date_fr);

  select sum( ld.payment_amount)
  into STRICT ldc_amount
  from sc_lon_m_loan_card_detail ld
    , sc_lon_m_ucf_loan_card_item lu
    , sc_lon_m_loan_card lm
  where  ld.item_type_code = lu.item_type_code
  and ( ld.loan_payment_date between ldt_date_fr and ldt_date_to )
  and ld.loan_contract_no = lm.loan_contract_no
  and lm.loan_contract_no = as_conno;

  return coalesce(ldc_amount,0);
exception when others then CALL spa_dberror('fpa_gos_month_loan');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
